document.addEventListener(`DOMContentLoaded`,function(){let e=document.getElementById(`aatxt_typology`),t=e=>{document.querySelectorAll(`.plugin-option`).forEach(t=>{let n=t.querySelectorAll(`input, select, textarea`);t.classList.contains(`type-`+e)?(t.style.display=`block`,n.forEach(e=>{e.classList.contains(`notRequired`)||e.setAttribute(`required`,``)})):(t.style.display=`none`,n.forEach(e=>e.removeAttribute(`required`)))})};t(e.value),e.addEventListener(`change`,function(e){let n=e.target.value;t(n)})});